import json

# Load capital market symbols and company names
result_path = locals()['var_functions.query_db:48']
with open(result_path, 'r') as f:
    capital_market_data = json.load(f)

# Create company info dictionary
company_names = {}
for row in capital_market_data:
    symbol = row['Symbol']
    name = row['Company Description']
    for sep in [' specializes', ' is ', ' operates', ' provides', ' focuses', ' was founded', ', based in', ',']:
        if sep in name:
            name = name.split(sep)[0].strip()
            break
    company_names[symbol] = name

# Identify biotech and high-risk stocks to prioritize
biotech_stocks = []
for row in capital_market_data:
    symbol = row['Symbol']
    desc = row['Company Description'].lower()
    # Check for biotech/pharma keywords
    keywords = ['bio', 'pharma', 'therapeutic', 'medical', 'diagnostic', 'cancer', 'stem cell', 'clinical']
    if any(keyword in desc for keyword in keywords):
        biotech_stocks.append(symbol)

print('__RESULT__:')
print(json.dumps({
    'biotech_stocks': biotech_stocks[:15],
    'biotech_count': len(biotech_stocks),
    'company_names_sample': {s: company_names[s] for s in biotech_stocks[:10]}
}))

